import sys
import os
import shutil
import json

TICKS_PER_FRAME = 5
FUNCTIONS_DIR = "output"
OUTPUT_DIR = "datapack"
PACK_NAMESPACE = "mcvideoholo"
PACK_MCMETA = json.dumps(
    {
        "pack": {
            "description": f"Generated by {PACK_NAMESPACE}",
            "min_format": [101, 1],
            "max_format": [101, 1],
        },
    },
    indent=2,
)
PACK_TICK_CONFIG = json.dumps(
    {
        "values": [f"{PACK_NAMESPACE}:tick"],
    },
    indent=2,
)

if not os.path.isdir(FUNCTIONS_DIR):
    print("Please run main.py first!")
    sys.exit(1)

if os.path.exists(OUTPUT_DIR):
    shutil.rmtree(OUTPUT_DIR)

os.makedirs(OUTPUT_DIR)
with open(os.path.join(OUTPUT_DIR, "pack.mcmeta"), "w") as f:
    f.write(PACK_MCMETA)

funcdir = os.path.join(OUTPUT_DIR, "data", PACK_NAMESPACE, "function")
tagfuncdir = os.path.join(OUTPUT_DIR, "data", "minecraft", "tags", "function")
shutil.copytree(FUNCTIONS_DIR, funcdir)
os.makedirs(tagfuncdir)

funcfiles = sorted(
    [f for f in os.listdir(funcdir) if f.startswith("f") and f.endswith(".mcfunction")]
)

with open(os.path.join(tagfuncdir, "tick.json"), "w", encoding="utf-8") as f:
    f.write(PACK_TICK_CONFIG)

with open(os.path.join(funcdir, "tick.mcfunction"), "w", encoding="utf-8") as f:
    f.write("# Play loop\n")
    f.write(f"scoreboard objectives add {PACK_NAMESPACE}_idx dummy\n")
    f.write(f"scoreboard objectives add {PACK_NAMESPACE}_tick dummy\n")
    f.write(f"scoreboard players add #i {PACK_NAMESPACE}_idx 0\n")
    f.write(f"scoreboard players add #max {PACK_NAMESPACE}_idx 0\n")
    f.write(f"scoreboard players add #t {PACK_NAMESPACE}_tick 1\n")
    f.write(
        "execute if score #max {}_idx matches 0 run scoreboard players set #max {}_idx {}\n".format(
            PACK_NAMESPACE, PACK_NAMESPACE, len(funcfiles)
        )
    )
    f.write(
        "execute if score #i {}_idx >= #max {}_idx run scoreboard players set #i {}_idx 0\n".format(
            PACK_NAMESPACE, PACK_NAMESPACE, PACK_NAMESPACE
        )
    )
    f.write(
        f"execute if score #t {PACK_NAMESPACE}_tick matches {TICKS_PER_FRAME}.. run function {PACK_NAMESPACE}:step\n"
    )
    f.write(
        f"execute if score #t {PACK_NAMESPACE}_tick matches {TICKS_PER_FRAME}.. run scoreboard players set #t {PACK_NAMESPACE}_tick 0"
    )

with open(os.path.join(funcdir, "step.mcfunction"), "w", encoding="utf-8") as f:
    f.write("# Frame step\n")
    f.write(f"scoreboard players add #i {PACK_NAMESPACE}_idx 1\n")
    f.write(
        f"execute if score #i {PACK_NAMESPACE}_idx >= #max {PACK_NAMESPACE}_idx run scoreboard players set #i {PACK_NAMESPACE}_idx 0\n"
    )

    for i, filename in enumerate(funcfiles):
        name = filename.replace(".mcfunction", "")
        f.write(
            f"execute if score #i {PACK_NAMESPACE}_idx matches {i} run function {PACK_NAMESPACE}:{name}\n"
        )

print(f"Done! Created Minecraft 26.1.2 datapack at {OUTPUT_DIR}/")
